import type { OpenClawConfig } from "openclaw/plugin-sdk/core";

/** Raw PulseBoard account credentials for a single board connection. */
export interface PulseBoardAccount {
  boardUrl: string;
  apiToken: string;
  username: string;
}

/** Top-level PulseBoard configuration with named accounts. */
export interface PulseBoardConfig {
  accounts: Record<string, PulseBoardAccount>;
}

/** A single inbound PulseBoard message. */
export interface PulseBoardMessage {
  id: string;
  boardId: string;
  authorId: string;
  content: string;
  timestamp: number;
}

// ---------------------------------------------------------------------------
// Resolved account type required by the channel plugin system.
// `createChatChannelPlugin` constrains TResolvedAccount to
// `{ accountId?: string | null }`.
// ---------------------------------------------------------------------------

export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  config: Partial<PulseBoardAccount>;
}

const DEFAULT_ACCOUNT_ID = "default";

export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | (Partial<PulseBoardAccount> & { enabled?: boolean; name?: string })
    | undefined;
  if (pbCfg?.apiToken) {
    return [DEFAULT_ACCOUNT_ID];
  }
  return [];
}

export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = opts.accountId ?? DEFAULT_ACCOUNT_ID;
  const pbCfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.pulseboard as
    | (Partial<PulseBoardAccount> & { enabled?: boolean; name?: string })
    | undefined;

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: pbCfg?.enabled !== false,
    configured: Boolean(pbCfg?.apiToken && pbCfg?.boardUrl),
    config: {
      boardUrl: pbCfg?.boardUrl,
      apiToken: pbCfg?.apiToken,
      username: pbCfg?.username,
    },
  };
}

