import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
  type ResolvedPulseBoardAccount,
} from "./types.js";

/**
 * PulseBoard channel plugin.
 *
 * PulseBoard is a fictional real-time bulletin board messaging platform where
 * users post messages to named "boards" and can send direct messages.
 */
export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    // Inline meta because getChatChannelMeta() only accepts core channel IDs.
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Connect to PulseBoard bulletin messaging.",
      order: 110,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: listPulseBoardAccountIds,
      resolveAccount: (cfg, accountId) => resolvePulseBoardAccount({ cfg, accountId }),
      isConfigured: (account) => account.configured,
    },
    setup: {
      applyAccountConfig: ({ cfg }) => cfg,
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[${ctx.account.accountId}] starting PulseBoard provider (${ctx.account.config.boardUrl ?? "no board URL"})`,
        );
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim() || undefined,
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, text }) => {
      const trimmedTo = to.trim();
      return attachChannelToResult("pulseboard", {
        to: trimmedTo,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});

